import { useState } from "react";
import ContactCard from "./components/ContactCard";
import { FaPencilAlt } from "react-icons/fa";
import "./App.css";

const initialContacts = [
  { id: 1, name: "Maria Siddiqua", email: "mariasiddiqua21@gmail.com", phone: "03364111054" },
  { id: 2, name: "Ali Khan", email: "ali.khan@example.com", phone: "03001234567" },
  { id: 3, name: "Sara Ahmed", email: "sara.ahmed@example.com", phone: "03111234567" },
];

function App() {
  const [contacts, setContacts] = useState(initialContacts);
  const [selectedContact, setSelectedContact] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const openContact = (contact) => {
    setSelectedContact(contact);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setSelectedContact(null);
    setIsModalOpen(false);
  };

  const deleteContact = () => {
    setContacts(contacts.filter(c => c.id !== selectedContact.id));
    closeModal();
  };

  return (
    <div className="app">

      <h2>My Contact Book</h2>

      {contacts.map((contact) => (
        <div key={contact.id} className="contact-row">
          <span>{contact.name}</span>

          <FaPencilAlt
            className="edit-icon"
            onClick={() => openContact(contact)}
          />
        </div>
      ))}

      {isModalOpen && (
        <div className="modal-overlay">
          <div className="modal-box">
            <ContactCard
              name={selectedContact.name}
              email={selectedContact.email}
              phone={selectedContact.phone}
              onDelete={deleteContact}
              onClose={closeModal}
            />
          </div>
        </div>
      )}

    </div>
  );
}

export default App;
